package gabikeys

import (
	"strings"
	"testing"
)

// A minimal but otherwise well-formed 1024-bit issuer public key, used as the
// basis for the malformed-Bases test cases below. Only the <Bases> block is
// mutated per test; everything else is valid so that the parse reaches and
// exercises Bases.UnmarshalXML.
const validPubKeyXML = `<?xml version="1.0" encoding="UTF-8" standalone="no"?>
<IssuerPublicKey xmlns="http://www.zurich.ibm.com/security/idemix">
   <Counter>0</Counter>
   <ExpiryDate>1700000000</ExpiryDate>
   <Elements>
      <n></n>
      <Z></Z>
      <S></S>
      <Bases num="6">
         <Base_0></Base_0>
         <Base_1></Base_1>
         <Base_2></Base_2>
         <Base_3></Base_3>
         <Base_4></Base_4>
         <Base_5></Base_5>
      </Bases>
   </Elements>
   <Features>
      <Epoch length="432000"></Epoch>
   </Features>
</IssuerPublicKey>`

// TestNewPublicKeyFromXMLValid is a sanity check that the unmodified key still
// parses successfully after the added validation in Bases.UnmarshalXML.
func TestNewPublicKeyFromXMLValid(t *testing.T) {
	pubk, err := NewPublicKeyFromXML(validPubKeyXML)
	if err != nil {
		t.Fatalf("expected valid public key to parse, got error: %v", err)
	}
	if len(pubk.R) != 6 {
		t.Fatalf("expected 6 bases, got %d", len(pubk.R))
	}
	for i, r := range pubk.R {
		if r == nil {
			t.Errorf("base %d is nil", i)
		}
	}
}

func TestBasesUnmarshalXMLRejectsMalformed(t *testing.T) {
	tests := []struct {
		name    string
		bases   string
		wantErr string
	}{
		{
			name: "non-numeric base",
			bases: `<Bases num="1">
         <Base_0>not-a-number</Base_0>
      </Bases>`,
			wantErr: "was not a base 10 integer",
		},
		{
			name: "empty base",
			bases: `<Bases num="1">
         <Base_0></Base_0>
      </Bases>`,
			wantErr: "was not a base 10 integer",
		},
		{
			name: "num attribute larger than element count",
			bases: `<Bases num="2">
         <Base_0>123</Base_0>
      </Bases>`,
			wantErr: "does not match number of base elements",
		},
		{
			name: "num attribute smaller than element count",
			bases: `<Bases num="1">
         <Base_0>123</Base_0>
         <Base_1>456</Base_1>
      </Bases>`,
			wantErr: "does not match number of base elements",
		},
	}

	const validBases = `<Bases num="6">
         <Base_0></Base_0>
         <Base_1></Base_1>
         <Base_2></Base_2>
         <Base_3></Base_3>
         <Base_4></Base_4>
         <Base_5></Base_5>
      </Bases>`

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			xmlInput := strings.Replace(validPubKeyXML, validBases, tc.bases, 1)
			if !strings.Contains(xmlInput, tc.bases) {
				t.Fatalf("test setup failed: could not substitute Bases block")
			}

			_, err := NewPublicKeyFromXML(xmlInput)
			if err == nil {
				t.Fatalf("expected an error for malformed Bases, got nil")
			}
			if !strings.Contains(err.Error(), tc.wantErr) {
				t.Fatalf("expected error containing %q, got: %v", tc.wantErr, err)
			}
		})
	}
}
